import React from "react";
import Navbar from "../components/Navbar";
import Register from "../pages/Register";
import { Route } from "react-router-dom";


const AppRouter = () => {
  return (
    <>
      <Navbar />
      <Routes>
        <Route path="/main" element={<main/>} />
      </Routes>
      <Register />
    </>
  );
};

export default AppRouter;
